	static SetAsMenuButton(element, menuData, callback, mousedown) {
		// todo - check if element is already menu button. If so just replace menudata, don't set new event handlers etc..
		function stopPropagation(ev) {
			ev.stopPropagation();
		};
		var eventName = mousedown ? "mousedown" : "click";
		
		if(menuData === null) {
			// detach any menu/event handlers from element, if exist
			element.removeEventListener("mousedown", stopPropagation);
			element.removeEventListener(eventName, openMenu);
			return;
		}
		
		function openMenu() {
			element.classList.add("pressed");
			if(!mousedown)
				element.addEventListener("mousedown", stopPropagation); // mousedown fires after click, then menu closes right after being opened
			element.removeEventListener(eventName, openMenu);
			var rect = element.getBoundingClientRect();
			UI.OpenMenu(menuData, {x:rect.x, y:rect.y, w:rect.width, h:rect.height}, closeMenu, element, mousedown);
		};
		function closeMenu(command) {
			element.classList.remove("pressed");
			if(!mousedown)
				element.removeEventListener("mousedown", stopPropagation);
			window.setTimeout(() => { // don't re-open menu straight away because click event will also fire after mouseup fires
				element.addEventListener(eventName, openMenu);
			}, 0);
			if(command)
				callback(command);
		};
		element.addEventListener(eventName, openMenu);
	}
	
